// Extract line items from WooCommerce order payload
const order = $input.first().json;
const lineItems = $input.first().json.body.line_items || [];

return lineItems.map(item => ({
  json: {
    order_id: order.body.id,
    sku: item.sku || item.product_id.toString(),
    product_name: item.name,
    qty_ordered: item.quantity
  }
}));

const orderedItem = $('Extract Line Items').item.json;
const inventoryRows = $('Read Inventory Sheet').all();

const match = inventoryRows.find(row => row.json.SKU === orderedItem.sku);
if (!match) throw new Error(`SKU not found: ${orderedItem.sku}`);

const currentStock = parseInt(match.json['Current Stock']) || 0;
const newStock = currentStock - orderedItem.qty_ordered;
const threshold = parseInt(match.json['Reorder Threshold']) || 5;

return [{
  json: {
    sku: orderedItem.sku,
    order_id: orderedItem.order_id,
    product_name: match.json['Product Name'],
    old_stock: currentStock,
    new_stock: newStock,
    threshold: threshold,
    is_low_stock: newStock <= threshold,
    supplier_email: match.json['Supplier Email'],
    reorder_qty: match.json['Reorder Qty'],
    qty_ordered: orderedItem.qty_ordered
  }
}];

// Parse Tally webhook payload
// Tally sends: body.data.fields[] where each field has label, type, value, options
const body = $input.first().json.body;
const fields = body?.data?.fields || [];

// Helper: get field by label
const getField = (label) => fields.find(f => f.label === label);

// Helper: resolve DROPDOWN selected option text from its ID
const resolveDropdown = (field) => {
  if (!field || !field.value || !field.options) return null;
  const selectedId = Array.isArray(field.value) ? field.value[0] : field.value;
  const match = field.options.find(opt => opt.id === selectedId);
  return match ? match.text : null;
};

// Extract each field
const skuField = getField('SKU');
const qtyField = getField('Quantity Received');
const supplierField = getField('Supplier Name');

const sku = resolveDropdown(skuField);
const qty_received = qtyField ? parseInt(qtyField.value) : null;
const supplier_name = resolveDropdown(supplierField) || 'Unknown Supplier';

// Validate
if (!sku) throw new Error('Could not resolve SKU from Tally dropdown');
if (!qty_received || isNaN(qty_received)) throw new Error('Missing or invalid Quantity Received');

return [{
  json: {
    sku: sku.toString().trim().toUpperCase(),
    qty_received,
    supplier_name,
    received_at: body.data.createdAt || new Date().toISOString(),
    tally_response_id: body.data.responseId
  }
}];

const restock = $('Parse & Validate Payload').item.json;
const inventoryRows = $('Read Current Inventory').all();

const match = inventoryRows.find(row => 
  row.json.SKU && row.json.SKU.toString().trim().toUpperCase() === restock.sku
);

if (!match) throw new Error(`SKU not found in inventory: ${restock.sku}`);

const currentStock = parseInt(match.json['Current Stock']) || 0;
const newStock = currentStock + restock.qty_received;

return [{
  json: {
    sku: restock.sku,
    product_name: match.json['Product Name'],
    old_stock: currentStock,
    new_stock: newStock,
    qty_received: restock.qty_received,
    supplier_name: restock.supplier_name,
    received_at: restock.received_at,
    threshold: parseInt(match.json['Reorder Threshold']) || 5
  }
}];

