// Split items into auto-order vs manual-approval buckets
const rows = $input.all();
const N8N_BASE_URL = 'https://n8n.sahcreatives.com';

const needsReorder = rows.filter(row => {
  const stock = parseInt(row.json['Current Stock']) || 0;
  const threshold = parseInt(row.json['Reorder Threshold']) || 5;
  return stock <= threshold;
});

if (needsReorder.length === 0) {
  return [{ json: { has_items: false, auto_items: [], manual_items: [], count: 0 } }];
}

const auto_items = [];
const manual_items = [];

needsReorder.forEach(r => {
  const autoAllowed = (r.json['Auto Ordering Allowed'] || '').toString().trim().toLowerCase();
  const item = {
    sku: r.json.SKU,
    product_name: r.json['Product Name'],
    current_stock: r.json['Current Stock'],
    threshold: r.json['Reorder Threshold'],
    reorder_qty: r.json['Reorder Qty'],
    supplier_email: r.json['Supplier Email']
  };
  if (autoAllowed === 'yes') {
    auto_items.push(item);
  } else {
    // Build approve/reject URLs for this specific item
    const encoded = encodeURIComponent(JSON.stringify(item));
    manual_items.push({
      ...item,
      approve_url: `${N8N_BASE_URL}/webhook/restock-approve?action=approve&data=${encoded}`,
      reject_url: `${N8N_BASE_URL}/webhook/restock-approve?action=reject&data=${encoded}`
    });
  }
});

return [{
  json: {
    has_items: true,
    count: needsReorder.length,
    auto_items,
    manual_items
  }
}];

const query = $input.first().json.query;
const action = query.action;
let item = {};
try {
  item = JSON.parse(decodeURIComponent(query.data || '{}'));
} catch(e) {
  throw new Error('Invalid item data in URL');
}

return [{
  json: {
    action,
    approved: action === 'approve',
    sku: item.sku,
    product_name: item.product_name,
    reorder_qty: item.reorder_qty,
    supplier_email: item.supplier_email,
    current_stock: item.current_stock
  }
}];
